trigger.body:
	v_Count NUMBER;
BEGIN

    IF AD_isTriggerEnabled()='N' THEN RETURN;
    END IF;

	IF INSERTING OR UPDATING THEN
		--Validamos que no exista el numero de autorizacion en otra factura
		SELECT COALESCE(COUNT(RF.*),0) INTO v_Count 
		FROM ssre_refundinvoice RF
		WHERE RF.withholdingauthorization = :NEW.withholdingauthorization;

		IF v_Count <> 0 THEN
			RAISE_APPLICATION_ERROR(-20000, '@SSRE_Duplicate_Authorization@');
		END IF;
		RETURN NEW;
	END IF;

    END SSRE_REFUNDINVOICE_AUTO_TRG
